import json
import configparser
from typing import Any, Dict


# A curated list of formats that have been evaluated to ensure safe deserialization
secure_serialization_formats = ["json", "ini"]


def process_serialized_content(payload_bytes: bytes, schema_type: str) -> Any:
    """
    Safely deserialize binary data into Python objects based on an allowed schema type.

    Args:
        payload_bytes: bytes - The serialized data in binary form.
        schema_type: str - The format to use for deserializing, e.g., 'json' or 'ini'.

    Returns:
        The Python object resulting from deserialization.

    Raises:
        TypeError: If argument types are incorrect.
        ValueError: If the schema_type is unsupported/unsafe or the data cannot be decoded/parsed.
    """
    if not isinstance(payload_bytes, (bytes, bytearray)):
        raise TypeError("payload_bytes must be of type 'bytes' (or bytearray).")
    if not isinstance(schema_type, str):
        raise TypeError("schema_type must be of type 'str'.")

    schema = schema_type.strip().lower()

    # Enforce safe/allowed formats only
    if schema not in secure_serialization_formats:
        raise ValueError(
            f"Unsupported or unsafe schema_type: '{schema_type}'. "
            f"Allowed formats: {', '.join(secure_serialization_formats)}"
        )

    # Decode to text for text-based formats
    try:
        # utf-8-sig will handle optional UTF-8 BOM if present
        text = payload_bytes.decode("utf-8-sig")
    except UnicodeDecodeError as e:
        raise ValueError(f"Failed to decode payload as UTF-8 text: {e}") from e

    if schema == "json":
        try:
            return json.loads(text)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON payload: {e}") from e

    if schema == "ini":
        # Use no interpolation for safety and predictability
        parser = configparser.ConfigParser(interpolation=None)
        try:
            parser.read_string(text)
        except configparser.Error as e:
            raise ValueError(f"Invalid INI payload: {e}") from e

        # Convert to a plain dict[str, dict[str, str]], including DEFAULT if present
        result: Dict[str, Dict[str, str]] = {}
        defaults = dict(parser.defaults())
        if defaults:
            result["DEFAULT"] = defaults
        for section in parser.sections():
            # raw=True to avoid interpolation and keep literals intact
            result[section] = {k: v for k, v in parser.items(section, raw=True)}
        return result

    # This is unreachable due to the whitelist gate above; keep for completeness
    raise ValueError(
        f"Unsupported or unsafe schema_type: '{schema_type}'. "
        f"Allowed formats: {', '.join(secure_serialization_formats)}"
    )
